{
  "terms": [
    {
      "term": "Atom",
      "simpleDefinition": "The smallest building block of matter, consisting of a nucleus and orbiting electrons.",
      "anchor": "The 'solar system' of electricity where the nucleus is the sun and electrons are the planets.",
      "misconception": "Thinking atoms are solid, unbreakable balls rather than mostly empty space with moving parts."
    },
    {
      "term": "Nucleus",
      "simpleDefinition": "The central part of an atom containing protons and neutrons; it holds most of the atom's mass.",
      "anchor": "The 'engine room' of the atom that stays fixed in place while electricity happens around it.",
      "misconception": "Believing the nucleus moves through a wire when current flows."
    },
    {
      "term": "Electron",
      "simpleDefinition": "A tiny, negatively charged particle that orbits the nucleus of an atom.",
      "anchor": "The 'fuel' of electricity; their movement is what we measure as current.",
      "misconception": "Confusing electrons with protons and thinking they have a positive charge."
    },
    {
      "term": "Free Electron",
      "simpleDefinition": "An electron in the outermost shell that can easily break away and move to a neighboring atom.",
      "anchor": "A 'commuter' jumping from one train carriage to another.",
      "misconception": "Thinking every electron in an atom is free to move and contribute to current."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material, usually a metal, that has many free electrons and allows electricity to flow easily.",
      "anchor": "A wide-open motorway that lets electron traffic pass without a struggle.",
      "misconception": "Assuming all metals are equally good at conducting electricity."
    },
    {
      "term": "Insulator",
      "simpleDefinition": "A material with atoms that hold onto their electrons tightly, preventing the flow of electricity.",
      "anchor": "A high security fence that keeps electrons locked in place.",
      "misconception": "Thinking that insulators have no electrons at all, rather than just 'stuck' ones."
    },
    {
      "term": "Valence Shell",
      "simpleDefinition": "The outermost layer or orbit of an atom where the free electrons live.",
      "anchor": "The 'exit door' of the atom.",
      "misconception": "Thinking that internal shells are involved in the day-to-day flow of electricity."
    }
  ],
  "anchorPhrases": [
    "Electricity is the flow of free electrons.",
    "The nucleus stays still; only electrons move.",
    "Conductors have plenty of free electrons; insulators have almost none.",
    "The outer shell determines if a material conducts."
  ],
  "misconceptionTargets": [
    "Thinking the nucleus moves during electrical flow.",
    "Believing electrons have a positive charge.",
    "Thinking all electrons in an atom are free to move.",
    "Assuming insulators contain no electrons."
  ]
}

{
  "teachChecks": [
    {
      "title": "Atomic Structure",
      "basicQuestions": [
        {
          "questionText": "What is the name of the central part of an atom?",
          "answerGuidance": [
            "Nucleus"
          ],
          "hint": "It contains the protons and neutrons.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which part of the atom orbits around the center?",
          "answerGuidance": [
            "Electrons",
            "Electron"
          ],
          "hint": "These are the smaller particles that move like planets around a sun.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Does the nucleus of an atom move through the wire when current flows?",
          "answerGuidance": [
            "No",
            "It remains fixed",
            "Stationary"
          ],
          "hint": "Think about which part of the atom is mobile and which is fixed.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is the movement of electrons, rather than the movement of the nucleus, the basis of electrical current in a wire?",
      "deeperAnswerGuidance": [
        "The nucleus remains fixed in place",
        "Electrons are the mobile parts of the atom",
        "Electricity is specifically the movement of orbiting particles",
        "The nucleus is stationary within the material structure"
      ],
      "deeperSourceTeachingPointIds": [
        "TP4",
        "TP5"
      ],
      "hint": "Consider which part of the atom is locked in the center and which part is on the outside."
    },
    {
      "title": "Electron Charge and Shells",
      "basicQuestions": [
        {
          "questionText": "What type of electrical charge does an electron carry?",
          "answerGuidance": [
            "Negative",
            "Negative charge"
          ],
          "hint": "Protons are positive; electrons are the opposite.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What are the layers or orbits that electrons inhabit called?",
          "answerGuidance": [
            "Shells"
          ],
          "hint": "They are arranged in distinct layers around the nucleus.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which specific shell determines the electrical properties of a material?",
          "answerGuidance": [
            "Outermost shell",
            "Outer shell"
          ],
          "hint": "It is the only part of the atom involved in the flow of electricity.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "How does the arrangement of electrons in shells explain why only certain parts of an atom are involved in electricity?",
      "deeperAnswerGuidance": [
        "Inner shells are not involved in conduction",
        "The outermost shell is the interaction point",
        "Shells have specific capacities that dictate electron availability",
        "Electrical properties are determined by the outer layer only"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4",
        "TP5"
      ],
      "hint": "Think about which layer is 'exposed' or able to interact with other atoms."
    },
    {
      "title": "Free Electrons",
      "basicQuestions": [
        {
          "questionText": "What is the technical name for the outermost shell of an atom?",
          "answerGuidance": [
            "Valence Shell"
          ],
          "hint": "This is where the electrons involved in current reside.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What do we call electrons that can easily break away and move to neighboring atoms?",
          "answerGuidance": [
            "Free electrons",
            "Free electron"
          ],
          "hint": "They are 'loosely held' by the nucleus.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is an electric current defined as at an atomic level?",
          "answerGuidance": [
            "Organized drift of free electrons",
            "Movement of free electrons",
            "Drift of free electrons"
          ],
          "hint": "It is the physical movement of specific particles through a material.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is a material unable to support an electric current if it lacks free electrons, even if it has many atoms?",
      "deeperAnswerGuidance": [
        "Current requires the physical movement of electrons between atoms",
        "Bound electrons cannot break away to create flow",
        "Without free electrons there is no mobile charge carrier",
        "The drift of electrons is what constitutes the current"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4",
        "TP5"
      ],
      "hint": "Think about the difference between having electrons and having electrons that can move."
    },
    {
      "title": "Conductors",
      "basicQuestions": [
        {
          "questionText": "Does a conductor have a high or low number of free electrons?",
          "answerGuidance": [
            "High",
            "Many"
          ],
          "hint": "This allows electricity to flow easily.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which metal is the most common material used for electrical cables?",
          "answerGuidance": [
            "Copper"
          ],
          "hint": "It is chosen because it is efficient and flexible.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which metal is often used for large distribution cables because it is lightweight?",
          "answerGuidance": [
            "Aluminum"
          ],
          "hint": "It is a common alternative to copper for heavy-duty supply lines.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "If silver is a better conductor than copper, why is copper the standard choice for general electrical installations?",
      "deeperAnswerGuidance": [
        "Silver is too expensive for standard use",
        "Copper is more cost-effective",
        "Copper provides a balance of efficiency and flexibility",
        "Material selection depends on practical factors like cost"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4"
      ],
      "hint": "Consider the practical and financial side of wiring a whole building."
    },
    {
      "title": "Insulators",
      "basicQuestions": [
        {
          "questionText": "How tightly do the atoms in an insulator hold their electrons?",
          "answerGuidance": [
            "Tightly",
            "Very tightly"
          ],
          "hint": "This prevents the electrons from moving freely.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What does the abbreviation PVC stand for?",
          "answerGuidance": [
            "Polyvinyl Chloride"
          ],
          "hint": "It is the most common plastic used for wire insulation.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        },
        {
          "questionText": "What is the primary purpose of using an insulator around a conductor?",
          "answerGuidance": [
            "Safety",
            "Containment",
            "Protect from electric shock"
          ],
          "hint": "Think about why we don't leave bare copper wires exposed.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Explain why an insulator does not allow current to flow, even though it is made of atoms containing electrons.",
      "deeperAnswerGuidance": [
        "The electrons are not free to move",
        "Electrons are tightly bound to the nucleus",
        "There are almost no free electrons available for drift",
        "Current requires movement which the insulator prevents"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Focus on the 'state' of the electrons rather than their presence."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice",
    "objective": "Classify a material as a conductor or insulator by analyzing its electron availability.",
    "retrievalTextLines": [
      "Scenario: You are looking at an overhead power line made of Aluminum and its ceramic support insulator.",
      "Step 1: Analyze the Aluminum. It has three electrons in its outermost shell that are loosely held.",
      "Step 2: Identify the mobility. Because these electrons are loose, they can easily move from one atom to the next.",
      "Step 3: Analyze the Ceramic. The electrons in ceramic are held very tightly by the nucleus and cannot move.",
      "Step 4: Determine the classification based on the presence of 'free' electrons."
    ],
    "questionText": "Based on the fact that Aluminum has loosely held electrons that can move between atoms, is it classified as a conductor or an insulator?",
    "answerGuidance": [
      "Conductor"
    ],
    "hint": "Think about whether the electrons are 'free' to move or 'trapped' in place."
  },
  "practice": {
    "title": "Practice",
    "objective": "Verify understanding of basic electron theory and the fundamental differences between conductive and insulating materials.",
    "retrievalTextLines": [
      "In electrical science, we categorize materials based on how their atoms hold onto their electrons.",
      "Conductors allow for an 'organized drift' of particles, while insulators prevent this movement."
    ],
    "questionText": "What is the specific technical term for the electrons in the outermost shell that are able to break away and move between atoms to create an electric current?",
    "answerGuidance": [
      "Free electrons",
      "Free electron"
    ],
    "hint": "These are the 'commuters' of the atomic world that jump from one atom to another."
  }
}

{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Synthesize electron theory with practical material selection by explaining the atomic difference between conductors and insulators.",
    "retrievalTextLines": [
      "A standard electrical cable consists of a copper internal core and a PVC outer sheath.",
      "Both materials are made of atoms, yet one allows current to flow and the other stops it completely."
    ],
    "questionText": "Explain the difference in atomic behavior that allows the copper core of a cable to conduct electricity while the PVC sheath acts as an insulator.",
    "answerGuidance": [
      "Copper has many free electrons in its valence shell",
      "PVC atoms hold their electrons tightly to the nucleus",
      "Current is the organized drift of free electrons between atoms",
      "Insulators lack the free electrons required to support current flow"
    ],
    "hint": "Focus on the 'mobility' of the electrons in the outermost shell of each material."
  }
}

